INSERT INTO content_translations (resource_type, resource_key, lang, text, updated_at) VALUES
('about_me_question', 'question1', 'kn', 'ನಿಮ್ಮ ಕುಟುಂಬದಲ್ಲಿ ಯಾರೊಂದಿಗೆ ನೀವು ಭಯ / ಸಂಕುಚಿತತೆ ಇಲ್ಲದೆ ಮುಕ್ತವಾಗಿ ನಿಮ್ಮ ಅಭಿಪ್ರಾಯಗಳನ್ನು ತಲುಪಿಸಿಕೊಳ್ಳಬಹುದು? ಮತ್ತು ಅವರೊಂದಿಗೆ ನಿಮಗೆ ಎಷ್ಟು ವಿಶ್ವಾಸವಿದೆ?', NOW()),
('about_me_question', 'question2', 'kn', 'ನಿಮ್ಮ ಕುಟುಂಬದವರನ್ನು ಬಿಟ್ಟು ಬೇರೆ ಯಾರೊಂದಿಗೆ ನೀವು ಭಯ / ಸಂಕುಚಿತತೆ ಇಲ್ಲದೆ ಮುಕ್ತವಾಗಿ ನಿಮ್ಮ ಅಭಿಪ್ರಾಯಗಳನ್ನು ಮತ್ತು ಭಾವನೆಗಳನ್ನು ಹಂಚಿಕೊಳ್ಳಬಹುದು?', NOW()),
('about_me_question', 'question3', 'kn', 'ಮನೆಯಲ್ಲಿ ನೀವು ಮಾಡುವ ಕೆಲಸಗಳು ಯಾವುವು? (ಉದಾ: ಕೃಷಿ ಚಟುವಟಿಕೆಗಳಲ್ಲಿ ಸಹಾಯ ಮಾಡುವುದು, ಅಂಗಡಿಯಿಂದ ತರಕಾರಿ ಮತ್ತು ದಿನಸಿ ಸಾಮಗ್ರಿಗಳನ್ನು ತರುವುದು, ಹಣ–ಕಾಸು ಕೆಲಸಗಳು, ಪ್ರಾಣಿಗಳ ಆರೈಕೆ, ನೀರು ತುಂಬಿಸುವುದು ಇತ್ಯಾದಿ)', NOW()),
('about_me_question', 'question4', 'kn', 'ನೀವು ಇಷ್ಟಪಟ್ಟು ಮಾಡುವ ಕೆಲಸಗಳು: a. ಶಾಲಾ ಅವಧಿಯಲ್ಲಿ b. ಶಾಲಾ ಅವಧಿಯ ನಂತರ (ಶಾಲಾ ಅವಧಿ ಪ್ರಾರಂಭವಾಗುವ ಮೊದಲು ಮತ್ತು ಶಾಲಾ ಅವಧಿ ಮುಗಿದ ನಂತರ)', NOW()),
('about_me_question', 'question5', 'kn', 'ಒಬ್ಬರೇ, ಸ್ವತಂತ್ರವಾಗಿ ಮಾಡಲು ಇಷ್ಟಪಡುವ ಕೆಲಸಗಳು ಯಾವುವು? (ಪ್ರತ್ಯೇಕವಾಗಿ ಒಬ್ಬರೇ ನಿರ್ವಹಿಸುವ ಕಾರ್ಯಗಳು)', NOW()),
('about_me_question', 'question6', 'kn', 'ನೀವು ಗುಂಪಿನಲ್ಲಿ / ನಿಮ್ಮ ಸ್ನೇಹಿತರೊಂದಿಗೆ ಯಾವ ಕೆಲಸಗಳನ್ನು ಮಾಡಲು ಇಷ್ಟಪಡುತ್ತೀರಿ?', NOW()),
('about_me_question', 'question7', 'kn', 'ನಿಮಗೆ ಶಾಲೆಯಲ್ಲಿ ಕಷ್ಟವೆನಿಸುವ ಚಟುವಟಿಕೆಗಳು ಯಾವುವು? ಬರೆಯಿರಿ.', NOW()),
('about_me_question', 'question8', 'kn', 'ಶಾಲೆಯ ಕೆಲಸ / ಚಟುವಟಿಕೆಗಳನ್ನು ಹೊರತುಪಡಿಸಿ ನಿಮಗೆ ಕಷ್ಟಕರವಾದ ಇನ್ನೇನು ಕೆಲಸಗಳಿವೆ?', NOW()),
('about_me_question', 'question9', 'kn', 'ನೀವು ಒಬ್ಬರೇ ಮಾಡಲು ಇಷ್ಟಪಡುವ ಕೆಲಸಗಳು ಯಾವುವು? ಉದಾಹರಣೆಗೆ, ಓದು, ಚಿತ್ರ ಬಿಡಿಸುವುದು, ಆಟಗಳು, ಇತ್ಯಾದಿ.', NOW()),
('about_me_question', 'question10', 'kn', 'ನೀವು ಇಷ್ಟಪಡುವ / ಇಷ್ಟವಿಲ್ಲದ ಚಟುವಟಿಕೆಗಳನ್ನು ಒಬ್ಬರೇ ಮಾಡಲು ಇಷ್ಟಪಡುತ್ತೀರಾ?', NOW()),
('about_me_question', 'question11', 'kn', '', NOW()), -- Hidden for Kannada (19 unique questions)
('about_me_question', 'question12', 'kn', 'ನಿಮ್ಮ ಬಗ್ಗೆ ನೀವೇ ಏನು ಹೇಳಿಕೊಳ್ಳುತ್ತೀರಿ? ನಿಮ್ಮಲ್ಲಿರುವ ಗುಣಗಳು ಯಾವುವು?', NOW()), -- Matches User Q11
('about_me_question', 'question13', 'kn', 'ಇವರು (ಪಾಲಕರು, ಶಿಕ್ಷಕರು, ಸ್ನೇಹಿತರು ಇತ್ಯಾದಿ) ನಿಮ್ಮ ಯಾವ ಗುಣಗಳನ್ನು ಇಷ್ಟಪಡುತ್ತಾರೆ ಎಂದು ಭಾವಿಸುತ್ತೀರಿ? ಪಟ್ಟಿ ಮಾಡಿ. (ಪೋಷಕರು, ಶಿಕ್ಷಕರು, ಸ್ನೇಹಿತರನ್ನು ಕೇಳಿ ಪರಿಶೀಲಿಸಿ.)', NOW()),
('about_me_question', 'question14', 'kn', 'ನಿಮ್ಮಲ್ಲಿನ ಯಾವ ಸ್ವಭಾವವನ್ನು ಸುಧಾರಣೆ / ಬದಲಾವಣೆ ಮಾಡಿಕೊಳ್ಳಲು ನೀವು ಬಯಸುತ್ತೀರಿ?', NOW()),
('about_me_question', 'question15', 'kn', 'ನಿಮ್ಮ ಯಾವ ಗುಣ ಅಥವಾ ಸ್ವಭಾವವನ್ನು ತಿದ್ದಿಕೊಳ್ಳಬೇಕು ಎಂದು ಇತರರು ಬಯಸುತ್ತಾರೆ ಅಥವಾ ಸಲಹೆ ನೀಡುತ್ತಾರೆ?', NOW()),
('about_me_question', 'question16', 'kn', 'ಭವಿಷ್ಯದಲ್ಲಿ ನಿಮಗೆ ಏನಾದರೂ / ಯಾರಾದರೂ ಆಗುವ ಅವಕಾಶ ಇದ್ದರೆ, ನೀವು ಏನಾಗಲು / ಯಾರಾಗಲು ಬಯಸುತ್ತೀರಿ?', NOW()),
('about_me_question', 'question17', 'kn', 'ನಿಮ್ಮ ಬಗ್ಗೆ ನೀವು ತೆಗೆದುಕೊಂಡ ಸಂದರ್ಶನವನ್ನು ನೆನಪಿಸಿಕೊಳ್ಳಿ. ನಿಮ್ಮ ಯಾವ ಕೆಲಸದಿಂದ ನಿಮಗೆ ಮೆಚ್ಚುಗೆ ದೊರೆಯಿತು? ಅದನ್ನು ಹೇಗೆ ಸಾಧಿಸಿದ್ದೀರಿ? ಸಂಕ್ಷಿಪ್ತವಾಗಿ ವಿವರಿಸಿ.', NOW()),
('about_me_question', 'question18', 'kn', 'ನೀವು ಇತ್ತೀಚೆಗೆ ಎದುರಿಸಿದ ಕಷ್ಟಕರ / ಸವಾಲಿನ ಪರಿಸ್ಥಿತಿಯ ಬಗ್ಗೆ ಯೋಚಿಸಿ. ಅದನ್ನು ನೀವು ಹೇಗೆ ಎದುರಿಸಿದ್ದೀರಿ ಅಥವಾ ಅದರಿಂದ ಹೇಗೆ ಪಾರಾಗಿದ್ದೀರಿ? ಅದರಿಂದ ಕಲಿತ ಪಾಠವೇನು?', NOW()),
('about_me_question', 'question19', 'kn', 'ಇತರರು ನಿಮ್ಮನ್ನು ತಪ್ಪಾಗಿ ತಿಳಿದ (ನಿಮ್ಮ ಬಗ್ಗೆ ತಪ್ಪು ಕಲ್ಪನೆ ಹೊಂದಿದ) ಸಂದರ್ಭವನ್ನು ನೆನಪಿಸಿಕೊಳ್ಳಿ. ನೀವು ಆ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸಿದ್ದೀರಿ ಮತ್ತು ಅದರಿಂದ ನೀವು ಏನು ಕಲಿತಿರಿ?', NOW()),
('about_me_question', 'question20', 'kn', 'ಸಾರಾಂಶದ ಆಧಾರದ ಮೇಲೆ ನಿಮ್ಮ ಬಗ್ಗೆ ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಬರೆಯಿರಿ. (ಪದಗಳು, ಚಿತ್ರಗಳು ಅಥವಾ ಚಿಹ್ನೆಗಳನ್ನು ಬಳಸಬಹುದು.)', NOW())
